import java.util.List;
import java.util.Map;
import java.util.ArrayList;
import java.util.stream.Collectors;
import java.util.Comparator;
import java.util.function.Function;

public class DocumentJoinerExample {

    public static void main(String[] args) {
        // Sample data:  Map of Queries to lists of lists of Documents
        Map<Query, List<List<Document>>> documentsForQuery = Map.of(
            new Query("query1"), List.of(List.of(new Document("Content 1", Map.of("score", 0.9))), List.of(new Document("Content 2", Map.of("score", 0.8)))),
            new Query("query2"), List.of(List.of(new Document("Content 3", Map.of("score", 0.7))))
        );

        // Create a ConcatenationDocumentJoiner
        DocumentJoiner documentJoiner = new ConcatenationDocumentJoiner();

        // Join the documents
        List<Document> joinedDocuments = documentJoiner.join(documentsForQuery);

        // Print the joined documents
        for (Document doc : joinedDocuments) {
            System.out.println("Document ID: " + doc.getId() + ", Content: " + doc.getContent() + ", Score: " + doc.getScore());
        }
    }
}

// Dummy classes to represent Document and Query for the example to compile
class Document {
    private String id;
